+.if defined(WITH_GNOMEVFS2)
+CONFIGURE_ARGS+=--enable-gnome-vfs
+USE_GNOME=	gnomevfs2
+PLIST_SUB+=	GNOMEVFS2=""
+.else
+CONFIGURE_ARGS+=--disable-gnome-vfs
+PLIST_SUB+=	GNOMEVFS2="@comment "
+.endif
