+ 
+-#define DEV_FD(dev)	(*(int *)dev->d_private)
++#if USE_UBLIO
++#define UBLIO_USE_API		1
++#include "ublio.h"
++#define UBLIO_DEFAULT_ENABLE	1
++#define UBLIO_DEFAULT_BLOCKSIZE	262144
++#define UBLIO_DEFAULT_ITEMS	64
++#define UBLIO_DEFAULT_GRACE	32
