++
++#if USE_ALIGNED_IO
++#define RAW_IO_ALIGNED(dev, offset, count)			\
++	(DEV_HANDLE(dev)->block_size == 0 ||			\
++	 ((offset) % DEV_HANDLE(dev)->block_size == 0 &&	\
