++		up.up_grace = UBLIO_DEFAULT_GRACE;
++	if ((xenv = getenv("UBLIO_SYNC_IO")) &&
++	    (xenv[0] == '0' || xenv[0] == '1') && xenv[1] == '\0')
++		up.up_sync_io = (xenv[0] == '1');
++	else
++		up.up_sync_io = UBLIO_DEFAULT_SYNC_IO;
++	up.up_priv	= &ufh->fd;
