++#else
++	if (S_ISBLK(sbuf.st_mode))
++		NDevSetBlock(dev);
++#endif /* USE_ALIGNED_IO */
++#if USE_LOCK
++	if (!NDevBlock(dev) && fcntl(DEV_FD(dev), F_SETLK, &flk)) {
