+ 		ntfs_log_debug("ntfs_device_unix_io_open: Could not lock %s for %s\n",
+ 				dev->d_name, NDevReadOnly(dev) ? "reading" : "writing");
+@@ -119,6 +283,16 @@
+ 					"close %s", dev->d_name);
+ 		goto err_out;
+ 	}
++#endif
++#if USE_UBLIO
++	if (use_ublio) {
