+ {
++#if USE_ALIGNED_IO
++	s64 abs_pos;
++
++	ntfs_log_trace("seek offset = 0x%llx, whence = %d.\n", offset, whence);
++	switch (whence) {
++	case SEEK_SET:
++		abs_pos = offset;
++		break;
++
++	case SEEK_CUR:
++		abs_pos = DEV_HANDLE(dev)->pos + offset;
